import asyncio
import json
import socket
import struct
import time
import zlib
import signal
from typing import Any, Dict, List, Tuple, Optional


MAGIC = b"GSQ1"
TYPE_STATUS = 0x01

FLAG_COMPRESSED = 0x01
FLAG_FRAGMENTED = 0x02

DEFAULT_MTU = 1200
HEADER_FMT = "!4sBBBBIHHH"  # magic, version, msg_type, flags, reserved, request_id, frag_index, frag_count, payload_len
HEADER_SIZE = struct.calcsize(HEADER_FMT)

VERSION = 1


def now_ms() -> int:
    return int(time.time() * 1000)


def safe_json_dumps(obj: Any) -> bytes:
    return json.dumps(obj, ensure_ascii=False, separators=(",", ":"), sort_keys=False).encode("utf-8")


def chunk_bytes(data: bytes, max_chunk: int) -> List[bytes]:
    if max_chunk <= 0:
        return [data]
    return [data[i:i + max_chunk] for i in range(0, len(data), max_chunk)]


