class UDPGameQueryServer(asyncio.DatagramProtocol):
    def __init__(
        self,
        game_state: GameState,
        *,
        mtu: int = DEFAULT_MTU,
        compress_threshold: int = 900,
        allow_compress: bool = True,
        response_pad_to: int = 0,
    ) -> None:
        self.transport: Optional[asyncio.DatagramTransport] = None
        self.game_state = game_state
        self.mtu = max(256, int(mtu))
        self.compress_threshold = max(0, int(compress_threshold))
        self.allow_compress = bool(allow_compress)
        self.response_pad_to = max(0, int(response_pad_to))

        self._sock: Optional[socket.socket] = None

    def connection_made(self, transport: asyncio.BaseTransport) -> None:
        self.transport = transport  # type: ignore[assignment]
        sock = self.transport.get_extra_info("socket")
        if isinstance(sock, socket.socket):
            self._sock = sock
            try:
                self._sock.setsockopt(socket.SOL_SOCKET, socket.SO_SNDBUF, 1 << 20)
                self._sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 1 << 20)
            except OSError:
                pass

    def datagram_received(self, data: bytes, addr: Tuple[str, int]) -> None:
        if len(data) < HEADER_SIZE:
            return

        try:
            magic, version, msg_type, flags, _reserved, request_id, frag_index, frag_count, payload_len = struct.unpack(
                HEADER_FMT, data[:HEADER_SIZE]
            )
        except struct.error:
            return

        if magic != MAGIC or version != VERSION:
            return

        if msg_type != TYPE_STATUS:
            return

        payload = data[HEADER_SIZE:HEADER_SIZE + payload_len]
        _ = payload
        self._send_status(addr, request_id)

    def _build_response_payload(self) -> bytes:
        snap = self.game_state.snapshot()
        payload = safe_json_dumps(snap)
        if self.response_pad_to and len(payload) < self.response_pad_to:
            pad_len = self.response_pad_to - len(payload)
            payload += b" " * pad_len
        return payload

    def _send_status(self, addr: Tuple[str, int], request_id: int) -> None:
        if not self.transport:
            return

        payload = self._build_response_payload()

        flags = 0
        if self.allow_compress and len(payload) >= self.compress_threshold:
            compressed = zlib.compress(payload, level=6)
            if len(compressed) + 32 < len(payload):
                payload = compressed
                flags |= FLAG_COMPRESSED

        max_payload_per_packet = self.mtu - HEADER_SIZE
        if max_payload_per_packet < 64:
            max_payload_per_packet = 64

        frags = chunk_bytes(payload, max_payload_per_packet)
        frag_count = len(frags)
        if frag_count > 1:
            flags |= FLAG_FRAGMENTED

        for idx, frag in enumerate(frags):
            header = struct.pack(
                HEADER_FMT,
                MAGIC,
                VERSION,
                TYPE_STATUS,
                flags,
                0,
                request_id & 0xFFFFFFFF,
                idx,
                frag_count,
                len(frag),
            )
            packet = header + frag
            try:
                self.transport.sendto(packet, addr)
            except (OSError, AttributeError):
                return


async def run_server(
    host: str = "0.0.0.0",
    port: int = 27015,
    mtu: int = DEFAULT_MTU,
    compress_threshold: int = 900,
    allow_compress: bool = True,
    response_pad_to: int = 0,
) -> None:
    loop = asyncio.get_running_loop()
    game_state = GameState()
    transport, _protocol = await loop.create_datagram_endpoint(
        lambda: UDPGameQueryServer(
            game_state,
            mtu=mtu,
            compress_threshold=compress_threshold,
            allow_compress=allow_compress,
            response_pad_to=response_pad_to,
        ),
        local_addr=(host, port),
        reuse_port=False,
        allow_broadcast=False,
    )

    stop_event = asyncio.Event()

    def _stop(*_args: Any) -> None:
        stop_event.set()

    try:
        loop.add_signal_handler(signal.SIGINT, _stop)
        loop.add_signal_handler(signal.SIGTERM, _stop)
    except (NotImplementedError, RuntimeError):
        pass

    try:
        await stop_event.wait()
    finally:
        transport.close()


def _parse_int(name: str, default: int) -> int:
    import os
    val = os.getenv(name)
    if val is None:
        return default
    try:
        return int(val)
    except ValueError:
        return default


def _parse_bool(name: str, default: bool) -> bool:
    import os
    val = os.getenv(name)
    if val is None:
        return default
    val = val.strip().lower()
    if val in ("1", "true", "yes", "y", "on"):
        return True
    if val in ("0", "false", "no", "n", "off"):
        return False
    return default


